```rust
fn fibonacci(n: u32) -> u64 {
    match n {
        0 => 0,
        1 => 1,
        _ => {
            let mut prev = 0;
            let mut curr = 1;
            for _ in 2..=n {
                let next = prev + curr;
                prev = curr;
                curr = next;
            }
            curr
        }
    }
}

// Example usage:
fn main() {
    for i in 0..20 {
        println!("fibonacci({}) = {}", i, fibonacci(i));
    }
}
```

