#[derive(Debug)]
enum NestedList {
    Elem(i32),
    List(Vec<NestedList>),
}

fn flatten(nested: &NestedList) -> Vec<i32> {
    let mut result = Vec::new();
    match nested {
        NestedList::Elem(val) => result.push(*val),
        NestedList::List(list) => {
            for item in list {
                result.extend(flatten(item));
            }
        }
    }
    result
}

