        NestedList::Elem(1),
        NestedList::List(vec![
            NestedList::Elem(2),
            NestedList::Elem(3)
        ]),
        NestedList::Elem(4)
    ]);

    let flat = flatten(&nested);
    println!("{:?}", flat); // Output: [1, 2, 3, 4]
}
```

---

