Certainly! Here’s a complete, working implementation of an LRU (Least Recently Used) cache in Rust. It uses `HashMap` for fast access and a doubly-linked list (`std::collections::LinkedList`) to track usage order. The cache is generic over keys (`K`) and values (`V`), and constrains `K` to `Eq + Hash + Clone`.

```rust
use std::collections::{HashMap, LinkedList};
use std::hash::Hash;

pub struct LruCache<K, V> {
    capacity: usize,
    map: HashMap<K, V>,
    usage: LinkedList<K>,
}

impl<K, V> LruCache<K, V>
where
    K: Eq + Hash + Clone,
{
    pub fn new(capacity: usize) -> Self {
        LruCache {
            capacity,
            map: HashMap::new(),
            usage: LinkedList::new(),
        }
    }

    pub fn get(&mut self, key: &K) -> Option<&V> {
        if self.map.contains_key(key) {
            self.promote(key);
            self.map.get(key)
        } else {
            None
        }
    }

    pub fn put(&mut self, key: K, value: V) {
        if self.map.contains_key(&key) {
            self.map.insert(key.clone(), value);
            self.promote(&key);
        } else {
            if self.map.len() == self.capacity {
                if let Some(old_key) = self.usage.pop_back() {
                    self.map.remove(&old_key);
                }
            }
            self.usage.push_front(key.clone());
            self.map.insert(key, value);
        }
    }

    pub fn contains_key(&self, key: &K) -> bool {
        self.map.contains_key(key)
    }

    fn promote(&mut self, key: &K) {
        let mut found = false;
        let mut new_usage = LinkedList::new();
        for k in self.usage.iter() {
            if k == key && !found {
                found = true;
                continue; // Skip the key to remove it
            }
            new_usage.push_back(k.clone());
        }
        new_usage.push_front(key.clone());
        self.usage = new_usage;
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn basic_lru_cache() {
        let mut cache = LruCache::new(2);
        cache.put(1, "one");
        cache.put(2, "two");
        assert_eq!(cache.get(&1), Some(&"one"));
        cache.put(3, "three");
        assert_eq!(cache.get(&2), None); // 2 was evicted
        assert_eq!(cache.get(&1), Some(&"one"));
        cache.put(4, "four");
        assert_eq!(cache.get(&3), None); // 3 was evicted
        assert_eq!(cache.get(&4), Some(&"four"));
        assert_eq!(cache.get(&1), Some(&"one"));
    }
}

fn main() {
    let mut cache = LruCache::new(2);
    cache.put("apple", 3);
    cache.put("banana", 5);
    println!("{:?}", cache.get(&"apple")); // Some(3)
    cache.put("pear", 7);
    println!("{:?}", cache.get(&"banana")); // None (evicted)
    println!("{:?}", cache.get(&"apple")); // Some(3)
    println!("{:?}", cache.get(&"pear")); // Some(7)
}
```

**Usage:**
- Instantiate with a capacity using `LruCache::new(capacity)`.
- Use `put(key, value)` to add items.
- Use `get(&key)` to retrieve items (and update LRU order).
- Oldest entries are evicted when capacity is exceeded.

**Note:**  
This implementation is not as efficient as one using intrusive linked lists (as `LinkedList` requires scanning to remove an item), but is simple and idiomatic for demonstration and moderate capacity. For max efficiency, consider crates like [`lru`](https://crates.io/crates/lru) for production use.

Here's a **complete Rust implementation** for serializing and deserializing a binary tree.

- The tree node is defined as `TreeNode`.
- Serialization outputs a comma-separated string in **preorder traversal** (`val,left,right`) syntax, using `"null"` for absent children.
- Deserialization parses the string back and rebuilds the tree.

You can run this in `main.rs` or playground.

```rust
use std::rc::Rc;
use std::cell::RefCell;

// Tree node definition
#[derive(Debug, PartialEq, Eq)]
pub struct TreeNode {
    pub val: i32,
    pub left: Option<Rc<RefCell<TreeNode>>>,
    pub right: Option<Rc<RefCell<TreeNode>>>,
}

impl TreeNode {
    pub fn new(val: i32) -> Rc<RefCell<TreeNode>> {
        Rc::new(RefCell::new(TreeNode { val, left: None, right: None }))
    }
}

// Serialize and Deserialize implementation
pub struct Codec;

impl Codec {
    /// Serializes a tree to a single string.
    pub fn serialize(root: Option<Rc<RefCell<TreeNode>>>) -> String {
        fn serialize_helper(node: Option<Rc<RefCell<TreeNode>>>, s: &mut String) {
            match node {
                Some(rc_node) => {
                    let node = rc_node.borrow();
                    s.push_str(&node.val.to_string());
                    s.push(',');
                    serialize_helper(node.left.clone(), s);
                    serialize_helper(node.right.clone(), s);
                }
                None => {
                    s.push_str("null,");
                }
            }
        }

        let mut res = String::new();
        serialize_helper(root, &mut res);
        // Remove trailing comma if needed
        if res.ends_with(',') {
            res.pop();
        }
        res
    }

    /// Deserializes your encoded data to tree.
    pub fn deserialize(data: String) -> Option<Rc<RefCell<TreeNode>>> {
        let mut vals: Vec<&str> = data.split(',').collect();
        // Wrap in slice as queue
        fn deserialize_helper(vals: &mut std::slice::Iter<&str>) -> Option<Rc<RefCell<TreeNode>>> {
            match vals.next() {
                Some(&"null") => None,
                Some(val) => {
                    let node = TreeNode::new(val.parse().unwrap());
                    node.borrow_mut().left = deserialize_helper(vals);
                    node.borrow_mut().right = deserialize_helper(vals);
                    Some(node)
                }
                None => None,
            }
        }
        deserialize_helper(&mut vals.iter())
    }
}

// --- Usage example ---

fn main() {
    // Construct a tree:    1
    //                   /     \
    //                  2       3
    //                         / \
    //                        4   5
    let node1 = TreeNode::new(1);
    let node2 = TreeNode::new(2);
    let node3 = TreeNode::new(3);
    let node4 = TreeNode::new(4);
    let node5 = TreeNode::new(5);

    node1.borrow_mut().left = Some(node2.clone());
    node1.borrow_mut().right = Some(node3.clone());
    node3.borrow_mut().left = Some(node4.clone());
    node3.borrow_mut().right = Some(node5.clone());

    let serialized = Codec::serialize(Some(node1.clone()));
    println!("Serialized: {}", serialized);

    let deserialized = Codec::deserialize(serialized.clone());
    println!("Deserialized: {:?}", deserialized);
}

```

**Output:**
```
Serialized: 1,2,null,null,3,4,null,null,5,null,null
Deserialized: Some(RefCell { value: TreeNode { val: 1, left: Some(RefCell { value: TreeNode { val: 2, left: None, right: None } }), right: Some(RefCell { value: TreeNode { val: 3, left: Some(RefCell { value: TreeNode { val: 4, left: None, right: None } }), right: Some(RefCell { value: TreeNode { val: 5, left: None, right: None } }) } }) } })
```

---

**Notes:**
- Uses `Rc<RefCell<_>>` to allow mutable tree structure.
- Serialization is **preorder** with `"null"` for missing nodes.
- Can be customized for other traversal strategies.

Certainly! Here’s a simple, usable implementation of a Trie (prefix tree) in Rust. This example supports insertion, search, and deletion of words.

```rust
use std::collections::HashMap;

#[derive(Default)]
struct TrieNode {
    children: HashMap<char, TrieNode>,
    is_end_of_word: bool,
}

#[derive(Default)]
pub struct Trie {
    root: TrieNode,
}

impl Trie {
    pub fn new() -> Self {
        Self { root: TrieNode::default() }
    }

    // Insert a word into the trie
    pub fn insert(&mut self, word: &str) {
        let mut node = &mut self.root;
        for c in word.chars() {
            node = node.children.entry(c).or_insert_with(TrieNode::default);
        }
        node.is_end_of_word = true;
    }

    // Search for a word in the trie
    pub fn search(&self, word: &str) -> bool {
        let mut node = &self.root;
        for c in word.chars() {
            match node.children.get(&c) {
                Some(child) => node = child,
                None => return false,
            }
        }
        node.is_end_of_word
    }

    // Search for a prefix in the trie
    pub fn starts_with(&self, prefix: &str) -> bool {
        let mut node = &self.root;
        for c in prefix.chars() {
            match node.children.get(&c) {
                Some(child) => node = child,
                None => return false,
            }
        }
        true
    }

    // Delete a word from the trie
    pub fn delete(&mut self, word: &str) -> bool {
        Self::delete_helper(&mut self.root, word, 0)
    }

    fn delete_helper(node: &mut TrieNode, word: &str, depth: usize) -> bool {
        if depth == word.len() {
            if !node.is_end_of_word {
                return false; // Word not found
            }
            node.is_end_of_word = false;
            return node.children.is_empty();
        }

        let c = match word.chars().nth(depth) {
            Some(ch) => ch,
            None => return false,
        };

        if let Some(child) = node.children.get_mut(&c) {
            let should_delete_child = Self::delete_helper(child, word, depth + 1);
            if should_delete_child {
                node.children.remove(&c);
                return node.children.is_empty() && !node.is_end_of_word;
            }
        }
        false
    }
}

// Example usage
fn main() {
    let mut trie = Trie::new();
    trie.insert("apple");
    trie.insert("app");

    println!("Search 'apple': {}", trie.search("apple")); // true
    println!("Search 'app': {}", trie.search("app")); // true
    println!("Search 'ap': {}", trie.search("ap")); // false
    println!("Starts with 'ap': {}", trie.starts_with("ap")); // true
    println!("Starts with 'apple': {}", trie.starts_with("apple")); // true

    trie.delete("apple");
    println!("Search 'apple' after deletion: {}", trie.search("apple")); // false
    println!("Search 'app' after deleting 'apple': {}", trie.search("app")); // true
}
```

**Features:**
- `insert(word)`: Inserts a word.
- `search(word)`: Checks if a word exists.
- `starts_with(prefix)`: Checks if any word starts with the prefix.
- `delete(word)`: Removes a word (returns true if the word was removed).

