Certainly! Here is a **complete, working implementation** of Dijkstra's shortest path algorithm in Rust. This code:

- Uses a min-heap priority queue (`BinaryHeap`) to efficiently select the next node.
- Represents the graph as an adjacency list.
- Handles graphs with non-negative edge weights.
- Finds shortest distances from a source node to all other nodes.

```rust
use std::collections::{BinaryHeap, HashMap};
use std::cmp::Ordering;

// Define a structure to represent a weighted edge
#[derive(Debug)]
struct Edge {
    node: usize,
    weight: u32,
}

// Entry for the priority queue: (distance, node)
#[derive(Eq, PartialEq)]
struct State {
    cost: u32,
    position: usize,
}

// Reverse ordering for min-heap
impl Ord for State {
    fn cmp(&self, other: &Self) -> Ordering {
        // Notice that we flip the ordering here
        other.cost.cmp(&self.cost)
            .then_with(|| self.position.cmp(&other.position))
    }
}

impl PartialOrd for State {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

/// Dijkstra's algorithm.
/// Returns a vector of shortest distances from the start node to every other node.
/// If unreachable, distance is `u32::MAX`.
fn dijkstra(adj: &Vec<Vec<Edge>>, start: usize) -> Vec<u32> {
    let mut dist = vec![u32::MAX; adj.len()];
    dist[start] = 0;

    let mut heap = BinaryHeap::new();
    heap.push(State { cost: 0, position: start });

    while let Some(State { cost, position }) = heap.pop() {
        // If this distance is outdated, skip
        if cost > dist[position] {
            continue;
        }

        // For each neighbor...
        for edge in &adj[position] {
            let next = State {
                cost: cost + edge.weight,
                position: edge.node,
            };

            // If found a shorter path, update
            if next.cost < dist[next.position] {
                dist[next.position] = next.cost;
                heap.push(next);
            }
        }
    }

    dist
}

// Example usage: sample graph and shortest paths
fn main() {
    // Graph with 5 nodes, represented as adjacency list.
    let adj = vec![
        vec![Edge { node: 1, weight: 10 }, Edge { node: 2, weight: 3 }],
        vec![Edge { node: 2, weight: 1 }, Edge { node: 3, weight: 2 }],
        vec![Edge { node: 1, weight: 4 }, Edge { node: 3, weight: 8 }, Edge { node: 4, weight: 2 }],
        vec![Edge { node: 4, weight: 7 }],
        vec![Edge { node: 3, weight: 9 }],
    ];

    let start = 0;
    let distances = dijkstra(&adj, start);

    for (node, d) in distances.iter().enumerate() {
        if *d == u32::MAX {
            println!("Node {} is unreachable from node {}", node, start);
        } else {
            println!("Shortest distance from node {} to node {} is {}", start, node, d);
        }
    }
}
```

