Certainly! Below is a **complete, working Rust implementation** of a **bounded blocking queue** using `Mutex` and `Condvar`. This queue supports `push` (enqueue) and `pop` (dequeue) operations, blocking when the queue is full or empty, respectively.

You can use this in multi-threaded environments.

---

```rust
use std::sync::{Mutex, Condvar, Arc};
use std::collections::VecDeque;
use std::thread;

pub struct BoundedBlockingQueue<T> {
    inner: Mutex<Inner<T>>,
    not_empty: Condvar,
    not_full: Condvar,
    capacity: usize,
}

struct Inner<T> {
    queue: VecDeque<T>,
}

impl<T> BoundedBlockingQueue<T> {
    /// Create a new bounded blocking queue with given capacity.
    pub fn new(capacity: usize) -> Self {
        assert!(capacity != 0, "Capacity must be non-zero");
        BoundedBlockingQueue {
            inner: Mutex::new(Inner {
                queue: VecDeque::with_capacity(capacity),
            }),
            not_empty: Condvar::new(),
            not_full: Condvar::new(),
            capacity,
        }
    }

    /// Push (enqueue) an item to the queue. Blocks if the queue is full.
    pub fn push(&self, item: T) {
        let mut guard = self.inner.lock().unwrap();
        while guard.queue.len() == self.capacity {
            guard = self.not_full.wait(guard).unwrap();
        }
        guard.queue.push_back(item);
        // Signal that queue is not empty
        self.not_empty.notify_one();
    }

    /// Pop (dequeue) an item from the queue. Blocks if the queue is empty.
    pub fn pop(&self) -> T {
        let mut guard = self.inner.lock().unwrap();
        while guard.queue.is_empty() {
            guard = self.not_empty.wait(guard).unwrap();
        }
        let item = guard.queue.pop_front().unwrap();
        // Signal that queue is not full
        self.not_full.notify_one();
        item
    }
}

// Example usage and test
fn main() {
    let queue = Arc::new(BoundedBlockingQueue::new(2));

    let queue1 = queue.clone();
    let producer = thread::spawn(move || {
        for i in 0..5 {
            println!("Producer pushing {}", i);
            queue1.push(i);
            println!("Producer pushed {}", i);
        }
    });

    let queue2 = queue.clone();
    let consumer = thread::spawn(move || {
        for _ in 0..5 {
            let val = queue2.pop();
            println!("Consumer popped {}", val);
        }
    });

    producer.join().unwrap();
    consumer.join().unwrap();
}
```

---

**How this works:**
- `push` blocks if the queue is full.
- `pop` blocks if the queue is empty.
- Uses `Mutex` for safety, and `Condvar` for blocking/waking threads.
- The example spawns a producer and a consumer thread to demonstrate the queue.

