Certainly! Here is a complete, working Rust implementation of an arithmetic expression evaluator. This code supports basic arithmetic (`+`, `-`, `*`, `/`), integer numbers (for simplicity), parentheses, and operator precedence.

You can run this as a standalone file (e.g., `main.rs`):

```rust
use std::str::Chars;
use std::iter::Peekable;
use std::io::{self, Write};

#[derive(Debug, PartialEq)]
enum Token {
    Plus,
    Minus,
    Mul,
    Div,
    LParen,
    RParen,
    Number(i64),
}

struct Lexer<'a> {
    input: Peekable<Chars<'a>>,
}

impl<'a> Lexer<'a> {
    fn new(s: &'a str) -> Self {
        Lexer { input: s.chars().peekable() }
    }

    fn next_token(&mut self) -> Option<Token> {
        while let Some(&ch) = self.input.peek() {
            match ch {
                ' ' | '\t' => { self.input.next(); }
                '+' => { self.input.next(); return Some(Token::Plus); }
                '-' => { self.input.next(); return Some(Token::Minus); }
                '*' => { self.input.next(); return Some(Token::Mul); }
                '/' => { self.input.next(); return Some(Token::Div); }
                '(' => { self.input.next(); return Some(Token::LParen); }
                ')' => { self.input.next(); return Some(Token::RParen); }
                '0'..='9' => {
                    return Some(self.lex_number());
                }
                _ => panic!("Unknown character: {}", ch),
            }
        }
        None
    }

    fn lex_number(&mut self) -> Token {
        let mut number = 0i64;
        while let Some(&ch) = self.input.peek() {
            if ch.is_ascii_digit() {
                number = number * 10 + (ch as i64 - '0' as i64);
                self.input.next();
            } else {
                break;
            }
        }
        Token::Number(number)
    }

    fn tokenize(s: &str) -> Vec<Token> {
        let mut lexer = Lexer::new(s);
        let mut tokens = Vec::new();
        while let Some(token) = lexer.next_token() {
            tokens.push(token);
        }
        tokens
    }
}

struct Parser<'a> {
    tokens: &'a [Token],
    pos: usize,
}

impl<'a> Parser<'a> {
    fn new(tokens: &'a [Token]) -> Self {
        Parser { tokens, pos: 0 }
    }

    fn parse(&mut self) -> i64 {
        self.parse_expr()
    }

    // expr = term ((+|-) term)*
    fn parse_expr(&mut self) -> i64 {
        let mut result = self.parse_term();
        while let Some(token) = self.peek() {
            match token {
                Token::Plus => {
                    self.pos += 1;
                    result += self.parse_term();
                }
                Token::Minus => {
                    self.pos += 1;
                    result -= self.parse_term();
                }
                _ => break,
            }
        }
        result
    }

    // term = factor ((*|/) factor)*
    fn parse_term(&mut self) -> i64 {
        let mut result = self.parse_factor();
        while let Some(token) = self.peek() {
            match token {
                Token::Mul => {
                    self.pos += 1;
                    result *= self.parse_factor();
                }
                Token::Div => {
                    self.pos += 1;
                    let divisor = self.parse_factor();
                    if divisor == 0 {
                        panic!("Division by zero");
                    }
                    result /= divisor;
                }
                _ => break,
            }
        }
        result
    }

    // factor = number | (expr)
    fn parse_factor(&mut self) -> i64 {
        match self.peek() {
            Some(Token::Number(_)) => {
                if let Token::Number(val) = self.next().unwrap() {
                    val
                } else {
                    unreachable!()
                }
            }
            Some(Token::LParen) => {
                self.pos += 1;
                let val = self.parse_expr();
                match self.peek() {
                    Some(Token::RParen) => self.pos += 1,
                    _ => panic!("Missing closing parenthesis"),
                }
                val
            }
            Some(Token::Minus) => {
                self.pos += 1;
                -self.parse_factor()
            }
            _ => panic!("Unexpected token at position {}", self.pos),
        }
    }

    fn peek(&self) -> Option<&Token> {
        self.tokens.get(self.pos)
    }

    fn next(&mut self) -> Option<&Token> {
        let tok = self.tokens.get(self.pos);
        self.pos += 1;
        tok
    }
}

fn eval_expression(s: &str) -> i64 {
    let tokens = Lexer::tokenize(s);
    let mut parser = Parser::new(&tokens);
    parser.parse()
}

fn main() {
    println!("Enter arithmetic expressions (e.g. 1 + 2 * (3 - 4)), or 'exit' to quit:");
    loop {
        print!("> ");
        io::stdout().flush().unwrap();
        let mut input = String::new();
        if io::stdin().read_line(&mut input).is_err() {
            break;
        }
        let input = input.trim();
        if input == "exit" {
            break;
        }
        if input.is_empty() {
            continue;
        }
        match std::panic::catch_unwind(|| eval_expression(input)) {
            Ok(result) => println!("{}", result),
            Err(_) => println!("Invalid expression!"),
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_basic() {
        assert_eq!(eval_expression("1+2"), 3);
        assert_eq!(eval_expression("2*3+4"), 10);
        assert_eq!(eval_expression("2*(3+4)"), 14);
        assert_eq!(eval_expression("10/(2+3)"), 2);
        assert_eq!(eval_expression("1 - 2 - 3"), -4);
        assert_eq!(eval_expression("(1 + 2) * (3 - 4)"), -3);
        assert_eq!(eval_expression("-5 + 2"), -3);
    }

    #[test]
    #[should_panic]
    fn test_division_by_zero() {
        eval_expression("1/0");
    }
}
```

