Sure! Here’s a simple, **lock-free stack** implemented in Rust using atomics. We'll use `Arc` for memory management and `AtomicPtr` for the lock-free top pointer. This implementation is for educational purposes—real-world concurrent stacks require careful handling of memory reclamation (see [hazard pointers](https://en.wikipedia.org/wiki/Hazard_pointer) or [epoch-based GC](https://docs.rs/crossbeam/latest/crossbeam/epoch/index.html)). Here, we rely on `Arc` for safe reclamation.

```rust
use std::sync::atomic::{AtomicPtr, Ordering};
use std::sync::Arc;
use std::ptr;

#[derive(Debug)]
struct Node<T> {
    value: T,
    next: Option<Arc<Node<T>>>,
}

pub struct LockFreeStack<T> {
    head: AtomicPtr<Node<T>>,
}

impl<T> LockFreeStack<T> {
    pub fn new() -> Self {
        LockFreeStack {
            head: AtomicPtr::new(ptr::null_mut()),
        }
    }

    pub fn push(&self, value: T) {
        let new_node = Arc::new(Node {
            value,
            next: None,
        });

        let mut current_head = self.head.load(Ordering::Acquire);

        loop {
            // Update next pointer with the current head.
            unsafe {
                Arc::get_mut(&mut Arc::clone(&new_node)).unwrap().next =
                    if current_head.is_null() {
                        None
                    } else {
                        Some(Arc::from_raw(current_head))
                    };
            }

            let new_ptr = Arc::into_raw(Arc::clone(&new_node)) as *mut Node<T>;

            // Try to update head.
            match self
                .head
                .compare_exchange(current_head, new_ptr, Ordering::Release, Ordering::Acquire)
            {
                Ok(_) => {
                    // Succeeded, prevent double-free of old head.
                    if !current_head.is_null() {
                        unsafe { Arc::from_raw(current_head); }
                    }
                    break;
                }
                Err(actual) => {
                    // Someone else changed head. Try again.
                    if !current_head.is_null() {
                        unsafe { Arc::from_raw(current_head); }
                    }
                    current_head = actual;
                }
            }
        }
    }

    pub fn pop(&self) -> Option<T> {
        let mut current_head = self.head.load(Ordering::Acquire);

        loop {
            if current_head.is_null() {
                return None;
            }

            let node = unsafe { Arc::from_raw(current_head) };

            let next_ptr = match &node.next {
                Some(next_arc) => Arc::into_raw(Arc::clone(next_arc)) as *mut Node<T>,
                None => ptr::null_mut(),
            };

            // Try to update head.
            match self.head.compare_exchange(
                current_head,
                next_ptr,
                Ordering::Acquire,
                Ordering::Relaxed,
            ) {
                Ok(_) => {
                    // Success! At this point, node is still alive (Arc refcount includes our local).
                    let value = unsafe {
                        // To take ownership, we need to Arc::try_unwrap. If refcount >1, we clone and return.
                        match Arc::try_unwrap(node) {
                            Ok(n) => n.value,
                            Err(n) => n.value, // fallback, will leak node (in practice, fine for demo).
                        }
                    };
                    if !next_ptr.is_null() {
                        unsafe { Arc::from_raw(next_ptr); } // Decrement refcount from our attempt.
                    }
                    return Some(value);
                }
                Err(actual) => {
                    // Someone else changed head. Try again.
                    if !current_head.is_null() {
                        unsafe { Arc::from_raw(current_head); }
                    }
                    current_head = actual;
                }
            }
        }
    }
}

impl<T> Drop for LockFreeStack<T> {
    fn drop(&mut self) {
        let mut current = self.head.load(Ordering::Relaxed);
        while !current.is_null() {
            unsafe {
                let node = Arc::from_raw(current);
                match &node.next {
                    Some(next_arc) => {
                        current = Arc::into_raw(Arc::clone(next_arc)) as *mut Node<T>;
                    }
                    None => {
                        current = ptr::null_mut();
                    }
                }
            }
        }
    }
}

// === Example usage ===
fn main() {
    use std::thread;

    let stack = Arc::new(LockFreeStack::new());

    let mut handles = vec![];

    // Spawn 4 threads to push values concurrently.
    for i in 0..4 {
        let stack = Arc::clone(&stack);
        handles.push(thread::spawn(move || {
            for j in 0..10 {
                stack.push(i * 10 + j);
            }
        }));
    }
    for handle in handles {
        handle.join().unwrap();
    }

    // Pop all the values.
    let mut popped = vec![];
    while let Some(val) = stack.pop() {
        popped.push(val);
    }

    println!("Popped values: {:?}", popped);
}
```

---
**Notes:**  
- *Memory Safety*: This implementation is safe because it always uses atomics and `Arc`. However, it leaks memory in edge cases when the stack is contended aggressively and nodes are cloned—see comments.
- *Usage*: This stack is `Send + Sync` for most `T: Send + Sync`, usable with multiple threads.
- *For production*: Prefer [crossbeam](https://github.com/crossbeam-rs/crossbeam) stacks which use epoch-based memory reclamation for efficiency.

