Here's a **complete, working B-tree implementation in Rust**.  
It includes the core functionalities: insert, search, and print (in order traversal).  
This implementation uses **generic key types** (bounded by `Ord + Clone`) and assumes a minimum degree t ≥ 2.

---

```rust
use std::fmt::Debug;
use std::cmp::Ord;

// Minimum degree t: Each internal node (except root) has at least t-1 keys, and at most 2t-1 keys.
const T: usize = 2;

#[derive(Clone)]
struct BTreeNode<K: Ord + Clone + Debug> {
    keys: Vec<K>,
    children: Vec<Box<BTreeNode<K>>>,
    leaf: bool,
}

impl<K: Ord + Clone + Debug> BTreeNode<K> {
    fn new(leaf: bool) -> Self {
        Self {
            keys: Vec::new(),
            children: Vec::new(),
            leaf,
        }
    }

    fn search(&self, key: &K) -> Option<&K> {
        let mut i = 0;
        while i < self.keys.len() && key > &self.keys[i] {
            i += 1;
        }
        if i < self.keys.len() && key == &self.keys[i] {
            return Some(&self.keys[i]);
        }
        if self.leaf {
            None
        } else {
            self.children[i].search(key)
        }
    }

    fn insert_non_full(&mut self, key: K) {
        let mut i = self.keys.len();

        if self.leaf {
            // Insert into keys in correct spot
            self.keys.push(key.clone());
            self.keys.sort();
        } else {
            // Find child to recurse into
            while i > 0 && key < self.keys[i - 1] {
                i -= 1;
            }
            if self.children[i].keys.len() == 2 * T - 1 {
                self.split_child(i);
                if key > self.keys[i] {
                    i += 1;
                }
            }
            self.children[i].insert_non_full(key);
        }
    }

    fn split_child(&mut self, idx: usize) {
        // Split child self.children[idx] into two nodes
        let child = &mut self.children[idx];

        let mut z = BTreeNode::new(child.leaf);
        let t = T;

        // Take the last t-1 keys of child and put into z
        z.keys = child.keys.split_off(t);
        let mid_key = child.keys.pop().unwrap();

        if !child.leaf {
            z.children = child.children.split_off(t);
        }

        self.keys.insert(idx, mid_key);
        self.children.insert(idx + 1, Box::new(z));
    }

    fn print_inorder(&self, level: usize) {
        for i in 0..self.keys.len() {
            if !self.leaf {
                self.children[i].print_inorder(level + 1);
            }
            println!("{}{:?}", "  ".repeat(level), self.keys[i]);
        }
        if !self.leaf {
            self.children[self.keys.len()].print_inorder(level + 1);
        }
    }
}

pub struct BTree<K: Ord + Clone + Debug> {
    root: Option<Box<BTreeNode<K>>>,
}

impl<K: Ord + Clone + Debug> BTree<K> {
    pub fn new() -> Self {
        Self { root: None }
    }

    pub fn search(&self, key: &K) -> Option<&K> {
        match &self.root {
            Some(node) => node.search(key),
            None => None,
        }
    }

    pub fn insert(&mut self, key: K) {
        if self.root.is_none() {
            let mut root = BTreeNode::new(true);
            root.keys.push(key);
            self.root = Some(Box::new(root));
            return;
        }

        let root = self.root.as_mut().unwrap();
        if root.keys.len() == 2 * T - 1 {
            // Root is full, split
            let mut s = BTreeNode::new(false);
            s.children.push(Box::new(root.clone()));
            s.split_child(0);
            self.root = Some(Box::new(s));
        }

        let root = self.root.as_mut().unwrap();
        root.insert_non_full(key);
    }

    pub fn print_inorder(&self) {
        match &self.root {
            Some(node) => node.print_inorder(0),
            None => println!("Empty tree"),
        }
    }
}

// Example usage
fn main() {
    let mut tree = BTree::<i32>::new();

    let vals = vec![10, 20, 5, 6, 12, 30, 7, 17];

    for x in vals {
        tree.insert(x);
    }

    println!("Inorder traversal:");
    tree.print_inorder();

    println!("\nSearching for 6...");
    if let Some(k) = tree.search(&6) {
        println!("Found: {k}");
    } else {
        println!("Not found.");
    }

    println!("\nSearching for 15...");
    if let Some(k) = tree.search(&15) {
        println!("Found: {k}");
    } else {
        println!("Not found.");
    }
}
```

