```rust
use rand::{thread_rng, Rng};
use std::{collections::HashMap, time::Duration};
use tokio::time::{sleep, timeout};
use crossbeam_channel::{unbounded, Sender, Receiver};

const NUM_NODES: usize = 5;
const ELECTION_TIMEOUT_MIN: u64 = 150;
const ELECTION_TIMEOUT_MAX: u64 = 300;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum State {
    Follower,
    Candidate,
    Leader,
}

#[derive(Debug)]
struct RaftNode {
    id: usize,
    term: u64,
    state: State,
    voted_for: Option<usize>,
    tx: Sender<Message>,
    rx: Receiver<Message>,
    peer_txs: HashMap<usize, Sender<Message>>,
}

#[derive(Debug, Clone)]
enum Message {
    RequestVote {
        term: u64,
        candidate_id: usize,
        reply_tx: Sender<Message>,
    },
    RequestVoteReply {
        term: u64,
        vote_granted: bool,
    },
    // Heartbeat from Leader to Followers (AppendEntries simplified)
    Heartbeat {
        term: u64,
        leader_id: usize,
    },
}

impl RaftNode {
    fn new(
        id: usize,
        tx: Sender<Message>,
        rx: Receiver<Message>,
        peer_txs: HashMap<usize, Sender<Message>>,
    ) -> Self {
        Self {
            id,
            term: 0,
            state: State::Follower,
            voted_for: None,
            tx,
            rx,
            peer_txs,
        }
    }

    fn election_timeout() -> Duration {
        let mut rng = thread_rng();
        let dur = rng.gen_range(ELECTION_TIMEOUT_MIN..ELECTION_TIMEOUT_MAX);
        Duration::from_millis(dur)
    }

    async fn run(mut self) {
        let mut election_timer = Self::election_timeout();

        loop {
            match self.state {
                State::Follower => {
                    // Wait for heartbeat or RequestVote, or timeout
                    let t = election_timer;
                    match timeout(t, async {
                        let msg = self.rx.recv().unwrap();
                        msg
                    }).await {
                        Ok(msg) => {
                            match msg {
                                Message::Heartbeat { term, leader_id: _ } => {
                                    if term >= self.term {
                                        self.term = term;
                                        self.state = State::Follower;
                                        self.voted_for = None;
                                        election_timer = Self::election_timeout();
                                    }
                                }
                                Message::RequestVote { term, candidate_id, reply_tx } => {
                                    if term > self.term {
                                        self.term = term;
                                        self.state = State::Follower;
                                        self.voted_for = None;
                                    }

                                    let mut vote_granted = false;
                                    if term == self.term {
                                        if self.voted_for.is_none() || self.voted_for == Some(candidate_id) {
                                            self.voted_for = Some(candidate_id);
                                            vote_granted = true;
                                            election_timer = Self::election_timeout();
                                        }
                                    }
                                    let _ = reply_tx.send(Message::RequestVoteReply {
                                        term: self.term,
                                        vote_granted,
                                    });
                                }
                                _ => {}
                            }
                        }
                        Err(_) => {
                            // Timeout: initiate election!
                            self.state = State::Candidate;
                            println!("Node {} election timeout, becoming CANDIDATE (term {})", self.id, self.term+1);
                        }
                    }
                }
                State::Candidate => {
                    self.term += 1;
                    self.voted_for = Some(self.id);
                    let mut votes = 1; // Vote for self
                    let (reply_tx, reply_rx) = unbounded();

                    // Send RequestVote to peers
                    for (&peer_id, peer_tx) in &self.peer_txs {
                        let msg = Message::RequestVote {
                            term: self.term,
                            candidate_id: self.id,
                            reply_tx: reply_tx.clone(),
                        };
                        let _ = peer_tx.send(msg);
                    }

                    let majority = NUM_NODES/2 + 1;
                    let election_deadline = tokio::time::Instant::now() + Self::election_timeout();
                    while tokio::time::Instant::now() < election_deadline {
                        if let Ok(msg) = reply_rx.recv_timeout(Duration::from_millis(20)) {
                            if let Message::RequestVoteReply { term, vote_granted } = msg {
                                if term > self.term {
                                    self.term = term;
                                    self.state = State::Follower;
                                    self.voted_for = None;
                                    break;
                                }
                                if vote_granted {
                                    votes += 1;
                                    if votes >= majority {
                                        self.state = State::Leader;
                                        println!("Node {} becomes LEADER in term {}", self.id, self.term);
                                        break;
                                    }
                                }
                            }
                        }
                        // Process incoming messages (heartbeats etc)
                        while let Ok(msg) = self.rx.try_recv() {
                            // If someone else became leader, revert
                            if let Message::Heartbeat { term, leader_id: _ } = msg {
                                if term >= self.term {
                                    self.term = term;
                                    self.state = State::Follower;
                                    self.voted_for = None;
                                    break;
                                }
                            }
                        }
                        if self.state == State::Follower {
                            break;
                        }
                    }

                    if self.state != State::Leader && self.state != State::Follower {
                        // Election failed; restart timer
                        election_timer = Self::election_timeout();
                        self.state = State::Follower;
                    }
                }
                State::Leader => {
                    // Send periodic heartbeats
                    for (&peer_id, peer_tx) in &self.peer_txs {
                        let msg = Message::Heartbeat {
                            term: self.term,
                            leader_id: self.id,
                        };
                        let _ = peer_tx.send(msg);
                    }
                    sleep(Duration::from_millis(50)).await;
                    // Listen for message (for completeness)
                    while let Ok(msg) = self.rx.try_recv() {
                        if let Message::RequestVote { term, candidate_id, reply_tx } = msg {
                            if term > self.term {
                                self.term = term;
                                self.state = State::Follower;
                                self.voted_for = None;
                                let _ = reply_tx.send(Message::RequestVoteReply {
                                    term: self.term,
                                    vote_granted: true,
                                });
                                break;
                            } else {
                                let _ = reply_tx.send(Message::RequestVoteReply {
                                    term: self.term,
                                    vote_granted: false,
                                });
                            }
                        }
                    }
                }
            }
        }
    }
}


#[tokio::main]
async fn main() {
    let mut txs = HashMap::new();
    let mut rxs = HashMap::new();

    // Create channels for each node
    for id in 0..NUM_NODES {
        let (tx, rx) = unbounded();
        txs.insert(id, tx);
        rxs.insert(id, rx);
    }

    // Create peer maps
    let mut handles = Vec::new();
    for id in 0..NUM_NODES {
        let tx = txs[&id].clone();
        let rx = rxs.remove(&id).unwrap();
        let mut peer_txs = HashMap::new();
        for (&peer_id, peer_tx) in &txs {
            if peer_id != id {
                peer_txs.insert(peer_id, peer_tx.clone());
            }
        }
        let node = RaftNode::new(id, tx, rx, peer_txs);
        handles.push(tokio::spawn(node.run()));
    }

    for h in handles {
        let _ = h.await;
    }
}
