Certainly! Below is a **complete, working Rust implementation** of Batcher's Odd-Even Mergesort. This algorithm is comparison-based and suitable for parallel execution; here, we'll implement it for slices with elements supporting `Ord + Copy`.

---

```rust
/// Implements Batcher's odd-even mergesort.
/// Usage: Call batcher_sort(&mut arr);
pub fn batcher_sort<T: Ord + Copy>(arr: &mut [T]) {
    let n = arr.len();
    if n < 2 {
        return;
    }
    if n == 2 {
        if arr[0] > arr[1] {
            arr.swap(0, 1);
        }
        return;
    }

    // Split array into two halves
    let mid = n / 2;
    batcher_sort(&mut arr[..mid]);
    batcher_sort(&mut arr[mid..]);
    odd_even_merge(arr, 0, n, 1);
}

/// Recursively merges the array according to Batcher's odd-even merge algorithm.
fn odd_even_merge<T: Ord + Copy>(arr: &mut [T], lo: usize, n: usize, r: usize) {
    if n > 1 {
        let m = n / 2;
        odd_even_merge(arr, lo, m, r * 2);
        odd_even_merge(arr, lo + r, m, r * 2);

        for i in (lo + r..lo + n - r).step_by(r * 2) {
            if arr[i] > arr[i + r] {
                arr.swap(i, i + r);
            }
        }
    }
}

#[cfg(test)]
