    #[test]
    fn test_batcher_sort_empty() {
        let mut arr: Vec<i32> = vec![];
        batcher_sort(&mut arr);
        assert_eq!(arr, vec![]);
    }

    #[test]
    fn test_batcher_sort_single() {
        let mut arr = vec![1];
        batcher_sort(&mut arr);
        assert_eq!(arr, vec![1]);
    }

    #[test]
    fn test_batcher_sort_basic() {
        let mut arr = vec![5, 3, 2, 4, 1];
        batcher_sort(&mut arr);
        assert_eq!(arr, vec![1, 2, 3, 4, 5]);
    }

    #[test]
    fn test_batcher_sort_even_length() {
        let mut arr = vec![2, 4, 6, 8, 3, 1, 7, 5];
        batcher_sort(&mut arr);
        assert_eq!(arr, vec![1, 2, 3, 4, 5, 6, 7, 8]);
    }

    #[test]
    fn test_batcher_sort_duplicates() {
        let mut arr = vec![3, 2, 3, 2, 3];
        batcher_sort(&mut arr);
        assert_eq!(arr, vec![2, 2, 3, 3, 3]);
    }
}

fn main() {
    let mut arr = vec![9, 5, 6, 1, 2, 4, 7, 8, 3];
    println!("Before: {:?}", arr);
    batcher_sort(&mut arr);
    println!("After:  {:?}", arr);
}
```

---

**Notes:**

- `batcher_sort` sorts the slice in place.
- The implementation handles any length, but odd-even mergesort is most efficient for powers of two; for other sizes, it works but isn't optimal.
- You can copy and run this code as a Rust project (include in `main.rs`).  
- A few tests are included for validation.

**References:**  
- Batcher's sorting network: [Wikipedia](https://en.wikipedia.org/wiki/Batcher_odd%E2%80%93even_mergesort)  
- The recursive merging is per the Batcher algorithm, not the standard merge-sort.

