Certainly! Here is a complete implementation of a **persistent (immutable) red-black tree** in Rust. This follows classic red-black tree rules, using immutable (persistent) data structures—so every nontrivial mutation returns a new tree, sharing structure with the old.

**Features**:
- Supports insert and lookup.
- Tree structure is persistent (immutable).
- Clean API for basic usage.

---

```rust
use std::rc::Rc;
use std::cmp::Ordering;

#[derive(Clone, Copy, PartialEq, Eq, Debug)]
pub enum Color {
    Red,
    Black,
}

type Link<K, V> = Option<Rc<Node<K, V>>>;

#[derive(Clone)]
struct Node<K, V> {
    color: Color,
    key: K,
    value: V,
    left: Link<K, V>,
    right: Link<K, V>,
}

/// Persistent (immutable) red-black tree.
pub struct RBTree<K: Ord, V> {
    root: Link<K, V>,
}

impl<K: Ord, V> RBTree<K, V> {
    pub fn new() -> Self {
        RBTree { root: None }
    }

    pub fn get(&self, key: &K) -> Option<&V> {
        let mut node = self.root.as_ref().map(|r| r.as_ref());
        while let Some(n) = node {
            match key.cmp(&n.key) {
                Ordering::Less => node = n.left.as_ref().map(|r| r.as_ref()),
                Ordering::Greater => node = n.right.as_ref().map(|r| r.as_ref()),
                Ordering::Equal => return Some(&n.value),
            }
        }
        None
    }

    pub fn insert(&self, key: K, value: V) -> Self {
        let root = insert_rec(self.root.clone(), key, value);
        // Ensure the root is always black
        let root = root.map(|node| {
            if node.color == Color::Red {
                Rc::new(Node { color: Color::Black, ..(*node).clone() })
            } else {
                node
            }
        });
        RBTree { root }
    }
}

fn insert_rec<K: Ord, V>(node: Link<K, V>, key: K, value: V) -> Link<K, V> {
    match node {
        None => {
            // Insert new red node
            Some(Rc::new(Node {
                color: Color::Red,
                key,
                value,
                left: None,
                right: None,
            }))
        }
        Some(rc_node) => {
            let n = rc_node.as_ref();
            match key.cmp(&n.key) {
                Ordering::Less => {
                    balance(Rc::new(Node {
                        color: n.color,
                        key: n.key.clone(),
                        value: n.value.clone(),
                        left: insert_rec(n.left.clone(), key, value),
                        right: n.right.clone(),
                    }))
                }
                Ordering::Greater => {
                    balance(Rc::new(Node {
                        color: n.color,
                        key: n.key.clone(),
                        value: n.value.clone(),
                        left: n.left.clone(),
                        right: insert_rec(n.right.clone(), key, value),
                    }))
                }
                Ordering::Equal => {
                    // Replace existing value
                    Some(Rc::new(Node {
                        color: n.color,
                        key: n.key.clone(),
                        value,
                        left: n.left.clone(),
                        right: n.right.clone(),
                    }))
                }
            }
        }
    }
}

// Balancing logic following Okasaki's functional RBT algorithm
fn balance<K: Ord, V>(node: Rc<Node<K, V>>) -> Link<K, V> {
    let n = node.as_ref();

    // Left child is red
    if is_red(&n.left) {
        let left = n.left.as_ref().unwrap().as_ref();
        // Left-Left case
        if is_red(&left.left) {
            return Some(Rc::new(Node {
                color: Color::Red,
                key: left.key.clone(),
                value: left.value.clone(),
                left: Some(Rc::new(Node {
                    color: Color::Black,
                    key: left.left.as_ref().unwrap().key.clone(),
                    value: left.left.as_ref().unwrap().value.clone(),
                    left: left.left.as_ref().unwrap().left.clone(),
                    right: left.left.as_ref().unwrap().right.clone(),
                })),
                right: Some(Rc::new(Node {
                    color: Color::Black,
                    key: n.key.clone(),
                    value: n.value.clone(),
                    left: left.right.clone(),
                    right: n.right.clone(),
                })),
            }));
        }
        // Left-Right case
        if is_red(&left.right) {
            let l_right = left.right.as_ref().unwrap().as_ref();
            return Some(Rc::new(Node {
                color: Color::Red,
                key: l_right.key.clone(),
                value: l_right.value.clone(),
                left: Some(Rc::new(Node {
                    color: Color::Black,
                    key: left.key.clone(),
                    value: left.value.clone(),
                    left: left.left.clone(),
                    right: l_right.left.clone(),
                })),
                right: Some(Rc::new(Node {
                    color: Color::Black,
                    key: n.key.clone(),
                    value: n.value.clone(),
                    left: l_right.right.clone(),
                    right: n.right.clone(),
                })),
            }));
        }
    }

    // Right child is red
    if is_red(&n.right) {
        let right = n.right.as_ref().unwrap().as_ref();
        // Right-Right case
        if is_red(&right.right) {
            return Some(Rc::new(Node {
                color: Color::Red,
                key: right.key.clone(),
                value: right.value.clone(),
                left: Some(Rc::new(Node {
                    color: Color::Black,
                    key: n.key.clone(),
                    value: n.value.clone(),
                    left: n.left.clone(),
                    right: right.left.clone(),
                })),
                right: Some(Rc::new(Node {
                    color: Color::Black,
                    key: right.right.as_ref().unwrap().key.clone(),
                    value: right.right.as_ref().unwrap().value.clone(),
                    left: right.right.as_ref().unwrap().left.clone(),
                    right: right.right.as_ref().unwrap().right.clone(),
                })),
            }));
        }
        // Right-Left case
        if is_red(&right.left) {
            let r_left = right.left.as_ref().unwrap().as_ref();
            return Some(Rc::new(Node {
                color: Color::Red,
                key: r_left.key.clone(),
                value: r_left.value.clone(),
                left: Some(Rc::new(Node {
                    color: Color::Black,
                    key: n.key.clone(),
                    value: n.value.clone(),
                    left: n.left.clone(),
                    right: r_left.left.clone(),
                })),
                right: Some(Rc::new(Node {
                    color: Color::Black,
                    key: right.key.clone(),
                    value: right.value.clone(),
                    left: r_left.right.clone(),
                    right: right.right.clone(),
                })),
            }));
        }
    }

    // No balancing needed
    Some(node)
}

fn is_red<K, V>(link: &Link<K, V>) -> bool {
    match link {
        Some(rc_node) => rc_node.color == Color::Red,
        None => false,
    }
}

// --- Testing ---

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_insert_and_lookup() {
        let tree = RBTree::new().insert(2, "two").insert(1, "one").insert(3, "three");
        assert_eq!(tree.get(&1), Some(&"one"));
        assert_eq!(tree.get(&2), Some(&"two"));
        assert_eq!(tree.get(&3), Some(&"three"));
        assert_eq!(tree.get(&4), None);
    }

    #[test]
    fn test_persistence() {
        let t1 = RBTree::new().insert(1, "a");
        let t2 = t1.insert(2, "b");
        let t3 = t2.insert(3, "c");

        assert_eq!(t1.get(&1), Some(&"a"));
        assert_eq!(t1.get(&2), None);

        assert_eq!(t2.get(&1), Some(&"a"));
        assert_eq!(t2.get(&2), Some(&"b"));
        assert_eq!(t2.get(&3), None);

        assert_eq!(t3.get(&1), Some(&"a"));
        assert_eq!(t3.get(&2), Some(&"b"));
        assert_eq!(t3.get(&3), Some(&"c"));
    }
}

// --- Example Main ---

fn main() {
    let mut tree = RBTree::new();
    tree = tree.insert(10, "ten");
    tree = tree.insert(5, "five");
    tree = tree.insert(20, "twenty");

    for k in [5, 10, 20, 42] {
        match tree.get(&k) {
            Some(v) => println!("{} => {}", k, v),
            None => println!("{} not found", k),
        }
    }
}
```

